const query = $json.query || '';
const telefone = $json.telefone || '';

// Lista de palavras a ignorar (stop words em português/espanhol)
const ignore = ['quero', 'apagar', 'excluir', 'deletar', 'buscar', 'encontrar', 'pode', 'quiere', 'borrar', 'eliminar', 'buscar', 'encontrar', 'puede', 'la', 'el', 'un', 'una', 'de', 'para'];

// Limpa a query: remove pontuação, converte pra minúsculo e filtra palavras curtas ou irrelevantes
let cleanQuery = query.toLowerCase()
  .replace(/[?!.,;]/g, '')
  .split(' ')
  .filter(word => word.length > 2 && !ignore.includes(word))
  .join(' ');

// Se a query ficar vazia, tenta manter a original sem os caracteres especiais
if (!cleanQuery) cleanQuery = query.replace(/[?!.,;]/g, '');

return {
  query: cleanQuery,
  original_query: query,
  telefone: telefone.replace('@s.whatsapp.net', '')
};

const results = $input.all();
if (results.length === 0) {
  return [{ json: { success: true, message: "🔍 No encontré transacciones que coincidan con '" + $node["receberDadosExterno"].json.query + "'." } }];
}

let msg = "🔍 *Encontré las siguientes transacciones:*\n\n";
results.forEach(item => {
  const row = item.json;
  const emoji = row.tipo === 'pago' ? '📉' : '📈';
  const monto = Number(row.monto).toLocaleString('es-CO');
  msg += `${emoji} *${row.descripcion}*\n💰 $${monto} | 📂 ${row.categoria}\n🆔 \`${row.transaccion_id}\`\n`;
  if (row.presupuesto_limite) {
    msg += `📊 *Presupuesto:* $${Number(row.presupuesto_limite).toLocaleString('es-CO')} (${row.presupuesto_periodo})\n`;
  }
  msg += "\n";
});

return [{ json: { success: true, message: msg.trim(), data: results.map(r => r.json) } }];
